using System.Collections;
using UnityEngine;

/// <summary>
/// Tarefa #35 — abre a loja "shop" (ShopUI) e espera até o jogador a fechar,
/// pausando o jogo entretanto (mesma lógica de pausa do diálogo —
/// GamePauseUtil, via ShopUI.OpenAndWait). Sem efeito se "shop" ou
/// ShopUI.Instance forem nulos.
/// </summary>
[System.Serializable]
public class Action_OpenShop : NpcAction
{
    public ShopData shop;

    public override IEnumerator Execute(NpcController npc)
    {
        if (shop == null || ShopUI.Instance == null)
        {
            if (shop == null) Debug.LogWarning("Action_OpenShop: 'shop' não atribuído.");
            else Debug.LogWarning("Action_OpenShop: nenhuma ShopUI encontrada na cena.");
            yield break;
        }

        yield return ShopUI.Instance.OpenAndWait(shop);
    }
}
